  ('optician-moex-01277', 'optician', 'optician-moex-109-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '度數為-7.75DS/-0.75DC×180隱形眼鏡的顧客，若想配戴眼鏡（vertexdistance15mm），何者度數最接近？', '["-8.00DS/-0.75DC×180", "-8.25DS/-1.00DC×180", "-8.50DS/-1.00DC×180", "-8.75DS/-1.00DC×180"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:32+00:00", "source_pdf_sha1": "1960c59d2916", "answer_pdf_sha1": "3a7e5b39127c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
